import React, { useState, useRef } from 'react';
import { FaUpload, FaCamera, FaSpinner, FaCheckCircle, FaTimesCircle, FaChartPie, FaChartBar } from 'react-icons/fa';

const CalorieUpload = ({ profile }) => {

    const fileInputRef = useRef(null);

    const [mealType, setMealType] = useState('');
    const [uploadedFile, setUploadedFile] = useState(null);
    const [prediction, setPrediction] = useState(null);
    const [loading, setLoading] = useState(false);
    const [uploadError, setUploadError] = useState('');
    const [uploadMessage, setUploadMessage] = useState('');

    /* ------------------ DAILY TARGETS ------------------ */
    const calculateDailyTargets = (dailyCalorieTarget, goal) => {
        const target = Number(dailyCalorieTarget);
        if (!target) return { protein: 0, fat: 0, carbs: 0 };

        const splits = {
            lose: [0.45, 0.30, 0.25],
            gain: [0.35, 0.30, 0.35],
            maintain: [0.40, 0.30, 0.30]
        };

        const [p, f, c] = splits[goal] || splits.maintain;

        return {
            protein: Math.round((target * p) / 4),
            fat: Math.round((target * f) / 9),
            carbs: Math.round((target * c) / 4),
        };
    };

    const dailyTargets = calculateDailyTargets(
        profile?.dailyCalorieTarget,
        profile?.goal
    );

    /* ------------------ FILE HANDLING ------------------ */
    const handleFileChange = (e) => {
        const file = e.target.files[0];
        if (file) {
            setUploadedFile(file);
            setPrediction(null);
            setUploadError('');
            setUploadMessage('');
        }
    };

    const handleSimulateUploadClick = () => {
        if (!mealType) {
            setUploadError("Please select a Meal Type first.");
            return;
        }
        fileInputRef.current.click();
    };

    /* ------------------ CNN SUBMIT ------------------ */
    const handleSubmit = async (e) => {
        e.preventDefault();
        if (!uploadedFile) return;

        setLoading(true);
        setUploadError('');
        setPrediction(null);

        try {
            const formData = new FormData();
            formData.append("file", uploadedFile);

            const response = await fetch(
                "http://localhost:5001/predict-calories-image",
                { method: "POST", body: formData }
            );

            if (!response.ok) throw new Error("CNN failed");

            const data = await response.json();
            setPrediction(data);
            setUploadMessage("Meal analyzed successfully!");

        } catch (err) {
            console.error(err);
            setUploadError("CNN service not reachable. Is FastAPI running?");
        } finally {
            setLoading(false);
        }
    };

    /* ------------------ MACRO FALLBACK ------------------ */
    const macro = prediction?.macroBreakdown || {
        protein: 0,
        fat: 0,
        carbohydrates: 0
    };

    const getMacroConicStyle = () => {
        const total = macro.protein + macro.fat + macro.carbohydrates;
        if (!total) return { background: 'conic-gradient(#333 0deg)' };

        const p = (macro.protein / total) * 360;
        const f = p + (macro.fat / total) * 360;

        return {
            background: `conic-gradient(
                #ef4444 0deg ${p}deg,
                #f59e0b ${p}deg ${f}deg,
                #3b82f6 ${f}deg 360deg
            )`,
        };
    };

    /* ------------------ UI ------------------ */
    return (
        <div className="space-y-6">

            {/* Upload Card */}
            <div className="bg-slate-900/40 p-6 rounded-2xl border border-slate-800">
                <form onSubmit={handleSubmit} className="space-y-6">

                    <select
                        value={mealType}
                        onChange={(e) => {
                            setMealType(e.target.value);
                            setUploadedFile(null);
                        }}
                        className="w-full p-3 rounded-xl bg-slate-800 text-white"
                    >
                        <option value="">-- Select Meal Type --</option>
                        <option>Breakfast</option>
                        <option>Lunch</option>
                        <option>Dinner</option>
                        <option>Snack</option>
                    </select>

                    <input
                        type="file"
                        ref={fileInputRef}
                        onChange={handleFileChange}
                        accept="image/*"
                        hidden
                    />

                    <div className="border-2 border-dashed p-6 rounded-xl text-center">
                        {uploadedFile ? (
                            <>
                                <FaCheckCircle className="mx-auto text-4xl text-green-400" />
                                <p className="text-green-400 mt-2">{uploadedFile.name}</p>
                                <button
                                    type="button"
                                    onClick={() => setUploadedFile(null)}
                                    className="text-red-400 text-sm mt-2"
                                >
                                    <FaTimesCircle /> Remove
                                </button>
                            </>
                        ) : (
                            <>
                                <FaCamera className="mx-auto text-4xl text-gray-500" />
                                <button
                                    type="button"
                                    onClick={handleSimulateUploadClick}
                                    className="mt-4 px-6 py-2 bg-yellow-500 rounded-xl font-bold"
                                >
                                    Select Image
                                </button>
                            </>
                        )}
                    </div>

                    <button
                        type="submit"
                        disabled={!uploadedFile || loading}
                        className="w-full py-3 bg-orange-600 rounded-xl font-bold text-white"
                    >
                        {loading ? <FaSpinner className="animate-spin mx-auto" /> : "Estimate Calories"}
                    </button>

                    {uploadError && <p className="text-red-400">{uploadError}</p>}
                </form>
            </div>

            {/* RESULT */}
            {prediction && (
                <div className="bg-slate-900/40 p-6 rounded-2xl border border-slate-800 space-y-4">
                    <h3 className="text-xl font-bold text-yellow-400">
                        🍽 {prediction.foodName}
                    </h3>
                    <p className="text-emerald-400 text-lg font-bold">
                        {prediction.caloriesEstimated} kcal
                    </p>
                    <p className="text-gray-400">
                        Confidence: {(prediction.confidence * 100).toFixed(1)}%
                    </p>

                    {/* Macro Visual (optional) */}
                    <div className="flex gap-6 items-center">
                        <div className="w-24 h-24 rounded-full" style={getMacroConicStyle()} />
                        <div className="text-sm text-gray-300">
                            Macros will be added next phase
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

export default CalorieUpload;
